package com.hospital.management.controller.appointment;import com.hospital.management.model.*;import com.hospital.management.service.*;import com.hospital.management.service.impl.AppointmentServiceImpl;import javax.servlet.*;import javax.servlet.annotation.WebServlet;import javax.servlet.http.*;import java.io.IOException;
@WebServlet("/appointments")public class AppointmentListServlet extends HttpServlet {private final AppointmentService service;public AppointmentListServlet(){this(new AppointmentServiceImpl());}public AppointmentListServlet(AppointmentService s){service=s;}protected void doGet(HttpServletRequest q,HttpServletResponse r)throws ServletException,IOException{int page=Math.max(1,AppointmentRequest.number(q.getParameter("page"),1)),size=Math.min(100,Math.max(1,AppointmentRequest.number(q.getParameter("size"),10)));PageRequest p=new PageRequest(page,size,q.getParameter("search"));q.setAttribute("appointmentPage",service.listAppointments(p,AppointmentRequest.id(q.getParameter("patientId")),AppointmentRequest.id(q.getParameter("doctorId")),AppointmentRequest.id(q.getParameter("departmentId")),AppointmentRequest.date(q.getParameter("dateFrom")),AppointmentRequest.date(q.getParameter("dateTo")),q.getParameter("status"),AppointmentRequest.user(q)));q.setAttribute("filters",q.getParameterMap());q.setAttribute("message",q.getParameter("message"));q.setAttribute("error",q.getParameter("error"));q.getRequestDispatcher("/WEB-INF/views/appointments/list.jsp").forward(q,r);}}
